        int i = Math.min(a.size(), b.size());
        while (i < a.size()) {
            maxPQ.add(a.get(i));
            i++;
        }
        while (i < b.size()) {
            minPQ.add(b.get(i));
            i++;
        }
        int maxPQSize = maxPQ.size();
        int minPQCurrSize = minPQ.size();
        List<Integer> finalAnswer = new ArrayList<>();
        for (int i = 0; i < c.size(); i++) {
